+fn action_severity(action: MemoryAction) -> u8 {
+    match action {
+        MemoryAction::None => 0,
+        MemoryAction::CompressIdle => 1,
+        MemoryAction::EvictToDisk => 2,
+        MemoryAction::EmergencyCleanup => 3,
+    }
